document.addEventListener("DOMContentLoaded",()=>{navegacionFija(),crearGaleria(),resaltarEnlace(),scrollNav()});const navegacionFija=()=>{const e=document.querySelector(".header"),t=document.querySelector(".sobre-festival");window.addEventListener("scroll",()=>{t.getBoundingClientRect().bottom<100?e.classList.add("fixed"):e.classList.remove("fixed")})},crearGaleria=()=>{const e=document.querySelector(".galeria-imagenes");for(let t=1;t<=16;t++){const a=document.createElement("PICTURE");a.innerHTML=`\n            <source srcset="dist/img/gallery/thumb/${t}.avif" type="image/avif">\n            <source srcset="dist/img/gallery/thumb/${t}.webp" type="image/webp">\n            <img loading="lazy" width="200" height="300" src="dist/img/gallery/thumb/${t}.jpg" alt="imagen galeria">\n        `,a.addEventListener("click",e=>{mostrarImagen(t)}),e.appendChild(a)}},mostrarImagen=e=>{const t=document.querySelector("body"),a=document.createElement("DIV"),l=document.createElement("PICTURE");a.classList.add("modal"),a.addEventListener("click",()=>{const e=document.querySelector(".modal");e?.classList.add("fade-out"),setTimeout(()=>{e?.remove(),t.classList.remove("overflow-hidden")},500)}),l.innerHTML=`\n        <source srcset="dist/img/gallery/full/${e}.avif" type="image/avif">\n        <source srcset="dist/img/gallery/full/${e}.webp" type="image/webp">\n        <img loading="lazy" width="200" height="300" src="dist/img/gallery/full/${e}.jpg" alt="imagen galeria">\n    `;const r=document.createElement("BUTTON");r.textContent="X",r.classList.add("modal-cerrar"),a.appendChild(l),a.appendChild(r),t.appendChild(a),t.classList.add("overflow-hidden")},resaltarEnlace=()=>{window.addEventListener("scroll",()=>{const e=document.querySelectorAll("section"),t=document.querySelectorAll(".navegacion-principal a");let a="";e.forEach(e=>{const t=e.offsetTop,l=e.clientHeight;window.scrollY>=t-l/3&&(a=e.id)}),t.forEach(e=>{console.log(e.attributes.href.value),e.getAttribute("href")===`#${a}`?e.classList.add("active"):e.classList.remove("active")})})},scrollNav=()=>{document.querySelectorAll(".navegacion-principal a").forEach(e=>{e.addEventListener("click",e=>{e.preventDefault();const t=e.target.getAttribute("href");document.querySelector(t).scrollIntoView({behavior:"smooth"})})})};